from matplotlib.patches import Rectanglefrom matplotlib.transforms import blended_transform_factoryfrom .utils import update_xlimfrom criresviz.plotting.style import (    ZORDER,    BOX_HEIGHT,    ORDER_TEXT_SIZE,    ALPHA,    COLORS,        )"""---------------------------------------------------------------------------------------------------------------- Low-level drawing functions for CRIRES+ settings ------------------------------------------------------------------------------------------------------------------"""def _draw_detector(ax, detector, setting, legend=False):    """    Draw a single CRIRES+ detector as a coloured wavelength segment.    Parameters    ----------    ax : matplotlib.axes.Axes        Axis on which to draw.    detector : Detector        Detector to display.    setting : str        Name of the CRIRES+ setting, used to determine the detector colour.    legend : bool, optional        Whether to include this detector in the legend.    """                transform = blended_transform_factory(        ax.transData,        ax.transAxes,    )        rectangle = Rectangle(        (detector.wavelength_min, 0),        detector.width,        BOX_HEIGHT,        facecolor=COLORS[setting][detector.number],        zorder=ZORDER["detector"],        transform=transform,        alpha=ALPHA,        label = setting if legend else None,    )    ax.add_patch(rectangle)    ##############################################    def _draw_order_label(ax, order):    """    Draw the order number above the central detector.    """    detector = order.detector2        transform = blended_transform_factory(        ax.transData,        ax.transAxes,    )        ax.text(        detector.wavelength_min + detector.width / 2,        1.02,        str(order.number),        ha="center",        va="center",        transform=transform,        zorder=ZORDER["labels"],        fontweight="bold",        fontsize=ORDER_TEXT_SIZE,    )    ##############################################    def _draw_setting(setting, ax, draw_order_labels=True):    """    Draw all echelle orders belonging to a CRIRES+ setting.    The wavelength limits of the axis are automatically expanded if    required before drawing the orders and detectors.    """    update_xlim(ax=ax, wavelength_range=setting.wavelength_range)        legend_added = False        for order in setting:        if draw_order_labels: _draw_order_label(ax, order)        for detector in order:            _draw_detector(                ax,                detector,                setting.name,                legend=not legend_added,            )            legend_added = True    return ax